// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function getWeatherIcon(condition: string): string {
  const iconMap: Record<string, string> = {
    'Sunny': '☀️',
    'Cloudy': '☁️',
    'Rainy': '🌧️',
    'Snowy': '❄️',
    'Stormy': '⛈️',
    'Windy': '💨',
    'Foggy': '🌫️',
    'Partly Cloudy': '🌤️',
  };
  return iconMap[condition] || '🌤️';
}

function useComponent(props: Props) {
  const defaultUnit = props.unit || 'C';
  return { ...props, unit: defaultUnit };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Stack gap={16}> 
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={8} align="center">
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.city}</Text>
          <Stack gap={4} align="center">
            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{state.temperature}°{state.unit}</Text>
            <Stack direction="horizontal" gap={8} align="center">
              <Text size="2xl">{getWeatherIcon(state.condition) || '🌤️'}</Text>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.condition}</Text>
            </Stack>
          </Stack>
          <Divider orientation="horizontal" margin={12} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
          <Stack direction="horizontal" gap={24} justify="center" align="center">
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{state.humidity}%</Text>
            </Stack>
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">{state.windSpeed} m/s</Text>
            </Stack>
          </Stack>
        </Stack>
      </Card>
      {state.forecast && state.forecast.length > 0 && (
        <Card shadow="sm" padding={16} radius="lg">
          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">5-Day Forecast</Text>
            <Stack direction="horizontal" gap={8} wrap>
              {state.forecast.map((day, idx) => (
                <Box key={idx} paddingX={12} paddingY={8} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8} style={{ flex: '1 1 auto', minWidth: '80px', textAlign: 'center' }}>
                  <Stack gap={4} align="center">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{day.day || 'N/A'}</Text>
                    <Text size="lg">{day.icon || '🌤️'}</Text>
                    <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">{day.high || '--'}° / {day.low || '--'}°{state.unit}</Text>
                  </Stack>
                </Box>
              ))}
            </Stack>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

