import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = (payload: ActionSubmitPayload) => {}; // Action handler (submit locally for now)

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', satisfaction: 0, features: [] as string[], comments: '' });
  const [errors, setErrors] = useState({ name: '', email: '' });
  const [fieldErrors, setFieldErrors] = useState({ name: '', email: '' }); // Real-time validation errors

  // Validation
  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);
  const isStep2Valid = formData.satisfaction > 0;
  const isStep3Valid = true; // No required fields on step 3
  const isStep4Valid = true; // No required fields on step 4

  // Real-time validation handler for Step 1
  const handleNameChange = (value: string) => {
    state.setFormData({ ...state.formData, name: value });
    const newErrors = { ...fieldErrors };
    newErrors.name = value.trim() === '' ? 'Name is required' : '';
    setFieldErrors(newErrors);
  };

  const handleEmailChange = (value: string) => {
    state.setFormData({ ...state.formData, email: value });
    const newErrors = { ...fieldErrors };
    newErrors.email = !validateEmail(value) && value !== '' ? 'Valid email is required' : '';
    setFieldErrors(newErrors);
  };

  const handleNext = () => {
    if (currentStep === 1) {
      const newErrors = { name: '', email: '' };
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!validateEmail(formData.email)) newErrors.email = 'Valid email is required';
      setErrors(newErrors);
      setFieldErrors(newErrors);
      if (isStep1Valid) setCurrentStep(2);
    } else if (currentStep === 2) {
      if (isStep2Valid) setCurrentStep(3);
    } else if (currentStep === 3) {
      setCurrentStep(4);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  const handleSubmit = () => {
    submit(formData);
  };

  return { currentStep, formData, setFormData, errors, setErrors, fieldErrors, handleNameChange, handleEmailChange, handleNext, handleBack, handleSubmit };

export default function Component(props: Props) {
  const state = useComponent(props);

  const renderStep = () => {
    switch (state.currentStep) {
      case 1:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 1: Personal Information</Heading>
            <FormField label='Name' required error={state.fieldErrors.name}>
              <Input
                label='Name'
                value={state.formData.name}
                onChange={state.handleNameChange}
                placeholder='Enter your name'
                error={state.fieldErrors.name}
              />
            </FormField>
            <FormField label='Email' required error={state.fieldErrors.email}>
              <Input
                label='Email'
                type='email'
                value={state.formData.email}
                onChange={state.handleEmailChange}
                placeholder='Enter your email'
                error={state.fieldErrors.email}
              />
            </FormField>
          </Stack>
        );
        );
      case 2:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 2: Satisfaction Rating</Heading>
            <RadioGroup
              label='How satisfied are you?'
              value={state.formData.satisfaction.toString()}
              onChange={(value) => state.setFormData({ ...state.formData, satisfaction: parseInt(value) })}
               options={(props.satisfactionLabels || []).map((label, i) => ({ value: (i + 1).toString(), label }))}
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 3: Feature Interests</Heading>
            <Stack gap={8}>
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={state.formData.features.includes(feature)}
                  onChange={(checked) => {
                    const updated = checked
                      ? [...state.formData.features, feature]
                      : state.formData.features.filter((f) => f !== feature);
                    state.setFormData({ ...state.formData, features: updated });
                  }}
                />
              ))}
            </Stack>
          </Stack>
        );
      case 4:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 4: Additional Comments</Heading>
            <TextArea
              label='Comments'
              value={state.formData.comments}
              onChange={(value) => state.setFormData({ ...state.formData, comments: value.slice(0, 500) })}
              placeholder='Enter any additional comments...'
              maxLength={500}
              showCount
              rows={6}
            />
          </Stack>
        );
       case 4:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 4: Additional Comments</Heading>
            <Card padding={16} shadow='sm'>
              <Stack gap={16}>
                <Box>
                  <Heading level={4}>Review Your Answers</Heading>
                </Box>
                <Stack gap={12}>
                  <Box>
                    <Text variant='label'>Name</Text>
                    <Text>{state.formData.name}</Text>
                  </Box>
                  <Divider />
                  <Box>
                    <Text variant='label'>Email</Text>
                    <Text>{state.formData.email}</Text>
                  </Box>
                  <Divider />
                  <Box>
                    <Text variant='label'>Satisfaction</Text>
                    <Text>{state.formData.satisfaction > 0 && state.formData.satisfaction <= (props.satisfactionLabels || []).length ? (props.satisfactionLabels || [])[state.formData.satisfaction - 1] : '(not selected)'}</Text>
                  </Box>
                  <Divider />
                  <Box>
                    <Text variant='label'>Features of Interest</Text>
                    <Stack gap={4}>
                      {state.formData.features.length > 0 ? (
                        state.formData.features.map((f) => <Badge key={f}>{f}</Badge>)
                      ) : (
                        <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant)'>None selected</Text>
                      )}
                    </Stack>
                  </Box>
                  <Divider />
                  <Box>
                    <Text variant='label'>Comments</Text>
                    <Text>{state.formData.comments || '(none)'}</Text>
                  </Box>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth='md' padding={24}>
      <Stack gap={24}>
        <div>
           <Text variant='label' color='var(--ggui-color-onSurfaceVariant)'>Step {state.currentStep} of 4</Text>
           <Progress value={state.currentStep} max={4} variant='default' size='md' />
        </div>
        {renderStep()}
        <Row gap={12} justify='between'>
          <Button
            variant='outline'
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
           {state.currentStep < 4 ? (
             <Button
               variant='primary'
               onClick={state.handleNext}
               disabled={
                 (state.currentStep === 1 && !state.formData.name.trim()) ||
                 (state.currentStep === 1 && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(state.formData.email)) ||
                 (state.currentStep === 2 && state.formData.satisfaction === 0)
               }
             >
               Next
             </Button>
           ) : (
             <Button variant='primary' onClick={state.handleSubmit}>
               Submit
             </Button>
           )}
        </Row>
      </Stack>
    </Container>
  );
}

