import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Manual event listener for real-time task updates
  const handleAgentData = (event: any) => {
    const data = event.detail as StreamTaskChanged;
    if (data.action === 'delete' && data.task?.id) {
      setTasks(prev => prev.filter(t => t.id !== data.task!.id));
    } else if (data.action === 'create' && data.task) {
      setTasks(prev => [...prev, data.task!]);
    } else if ((data.action === 'move' || data.action === 'edit') && data.task?.id) {
      setTasks(prev => prev.map(t => t.id === data.task!.id ? { ...t, ...data.task } : t));
    }
  };

  const [tasks, setTasks] = useState(props.tasks || []);
  const [newTaskForms, setNewTaskForms] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high' }>>({}); // Forms for 'Add Task' in each column
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');

  // Listen for real-time task updates from agent
  useEffect(() => {
    const listener = handleAgentData;
    window.addEventListener('ggui:agent-data', listener);
    return () => window.removeEventListener('ggui:agent-data', listener);
  }, []);

  // Compute tasks by column
  const tasksByColumn = React.useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns.forEach(col => {
      grouped[col.id || ''] = [];
    });
    tasks.forEach(task => {
      const colId = task.column || '';
      if (grouped[colId]) {
        grouped[colId].push(task);
      }
    });
    return grouped;
  }, [tasks, props.columns]);

  const totalTasks = tasks.length;
  const completedTasks = tasksByColumn[props.columns.find(c => c.name?.toLowerCase().includes('done'))?.id || '']?.length || 0;

  // Handlers
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    // Simulate sending to agent (would call taskUpdate() if wire hooks were available)
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
  }, []);

  const handleAddTask = useCallback((columnId: string) => {
    const form = newTaskForms[columnId];
    if (!form || !form.title.trim()) return;
    const newTask = {
      id: `task-${Date.now()}`,
      title: form.title,
      priority: form.priority,
      column: columnId,
      assignee: '',
      dueDate: undefined
    };
    // Simulate sending to agent (would call taskUpdate() if wire hooks were available)
    setTasks(prev => [...prev, newTask]);
    setNewTaskForms(prev => ({ ...prev, [columnId]: { title: '', priority: 'low' } }));
  }, [newTaskForms]);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    if (!newTitle.trim()) return;
    // Simulate sending to agent (would call taskUpdate() if wire hooks were available)
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
    setEditingTaskId(null);
    setEditingTitle('');
  }, [tasks]);

  const handleFormChange = useCallback((columnId: string, field: string, value: string) => {
    setNewTaskForms(prev => ({
      ...prev,
      [columnId]: { ...prev[columnId], [field]: value }
    }));
  }, []);

  return { tasks, tasksByColumn, totalTasks, completedTasks, newTaskForms, editingTaskId, editingTitle, handleMoveTask, handleAddTask, handleEditTask, handleFormChange, setEditingTaskId, setEditingTitle };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (<></>); // TODO: implement the UI here
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [props.elements, searchQuery]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const unique = new Set(props.elements.map((el) => el.category).filter(Boolean));
    return Array.from(unique).sort();
  }, [props.elements]);

  // Color mapping for categories
  const categoryColors: Record<string, string> = {
    'Nonmetal': 'var(--ggui-color-primary-100, #e0f2fe)',
    'Noble Gas': 'var(--ggui-color-success-100, #dcfce7)',
    'Alkali Metal': 'var(--ggui-color-warning-100, #fef3c7)',
    'Alkaline Earth Metal': 'var(--ggui-color-info-100, #cffafe)',
    'Transition Metal': 'var(--ggui-color-error-100, #fee2e2)',
    'Lanthanide': 'var(--ggui-color-primary-50, #f0f9ff)',
    'Actinide': 'var(--ggui-color-primary-200, #bae6fd)',
    'Halogen': 'var(--ggui-color-warning-50, #fffbeb)',
    'Metalloid': 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    'Metal': 'var(--ggui-color-outline, #d4d4d8)',
  };

  const getCategoryColor = (category?: string) => {
    return category && categoryColors[category]
      ? categoryColors[category]
      : 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  };

  const handleElementClick = useCallback((element: typeof props.elements[0]) => {
    setSelectedElement(element);
  }, []);

  const handleClearSearch = useCallback(() => {
    setSearchQuery('');
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    filteredElements,
    selectedElement,
    setSelectedElement,
    categories,
    getCategoryColor,
    handleElementClick,
    handleClearSearch,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={8}>
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Explore the elements. Click any element to view details.
          </Text>
        </Stack>

        {/* Search Section */}
        <Card shadow="md" padding={16} radius="lg">
          <SearchField
            value={state.searchQuery}
            onChange={state.setSearchQuery}
            placeholder="Search by name or symbol (e.g., 'Gold', 'Au')..."
            size="md"
          />
          {state.searchQuery && (
            <Stack direction="horizontal" gap={8} align="center" justify="between" style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Found {state.filteredElements.length} element{state.filteredElements.length !== 1 ? 's' : ''}
              </Text>
              <Button variant="ghost" size="xs" onClick={state.handleClearSearch}>
                Clear
              </Button>
            </Stack>
          )}
        </Card>

        {/* Legend */}
        <Card shadow="sm" padding={16} radius="lg" border={true}>
          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Element Categories
            </Text>
            <Stack direction="horizontal" gap={12} wrap={true}>
              {state.categories.map((category) => (
                <Box
                  key={category}
                  padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                  background={state.getCategoryColor(category)}
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  style={{
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  }}
                >
                  <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="medium">
                    {category}
                  </Text>
                </Box>
              ))}
            </Stack>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surface, #fafafa)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          {state.filteredElements.map((element) => {
            const gridRow = element.row || 1;
            const gridCol = element.col || 1;
            const bgColor = state.getCategoryColor(element.category);
            const isSelected = state.selectedElement?.atomicNumber === element.atomicNumber;

            return (
              <Box
                key={element.atomicNumber}
                as={Clickable}
                onClick={() => state.handleElementClick(element)}
                style={{
                  gridRow,
                  gridColumn: gridCol,
                  background: bgColor,
                  border: isSelected
