type ActionSendMessagePayload = { text: string; timestamp: string };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };

function useComponent(props: Props) {
  // State for messages and input
  const [messages, setMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on new messages
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  // Handle new messages from stream
  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail?.event === 'message' && customEvent.detail?.data) {
        setMessages(prev => [...prev, customEvent.detail.data]);
        scrollToBottom();
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, [scrollToBottom]);

  // Handle typing indicator from stream
  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      if (customEvent.detail?.event === 'typing' && customEvent.detail?.data) {
        const { sender, active } = customEvent.detail.data;
        setTypingUsers(prev => {
          const next = new Set(prev);
          if (active && sender) {
            next.add(sender);
          } else if (sender) {
            next.delete(sender);
          }
          return next;
        });
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const timestamp = new Date().toISOString();
      const payload: ActionSendMessagePayload = { text: inputText, timestamp };
      window.dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'sendMessage', payload } }));
      setInputText('');
    }
  }, [inputText]);

  // Handle Enter key in input
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Group consecutive messages from same sender
  const groupedMessages = React.useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ text?: string; timestamp?: string }> }> = [];
    messages.forEach(msg => {
      if (groups.length > 0 && groups[groups.length - 1].sender === msg.sender) {
        groups[groups.length - 1].messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({ sender: msg.sender, messages: [{ text: msg.text, timestamp: msg.timestamp }] });
      }
    });
    return groups;
  }, [messages]);

  return { messages, setMessages, inputText, setInputText, groupedMessages, typingUsers, handleSendMessage, handleKeyDown, scrollToBottom, messagesEndRef };
}

