interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {

  // State to track which stocks were recently updated (for flash animation)
  const [recentlyUpdated, setRecentlyUpdated] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<Map<string, NodeJS.Timeout>>(new Map());
  const [stocks, setStocks] = useState(props.stocks || []);
  const [currentMarketStatus, setCurrentMarketStatus] = useState<'open' | 'closed' | 'pre-market' | 'after-hours'>('closed');
  const [lastUpdatedTime, setLastUpdatedTime] = useState('N/A');

  // Listen for real-time stream events
  useEffect(() => {
    const handlePriceUpdate = (event: CustomEvent<StreamPriceUpdate>) => {
      const update = event.detail;
      // Check if this is a price update event (has symbol) vs other event types
      if (!update.symbol) return;
      setStocks(prev => {
        if (!prev) return prev;
        const updatedStocks = prev.map(stock =>
          stock.symbol === update.symbol
            ? {
                ...stock,
                price: update.price ?? stock.price,
                change: update.change ?? stock.change,
                changePercent: update.changePercent ?? stock.changePercent,
              }
            : stock
        );
        // Mark this stock as recently updated
        setRecentlyUpdated(prev => new Set([...prev, update.symbol]));
        // Clear the timeout if it exists, then set a new one
        const existingTimeout = updateTimeoutRef.current.get(update.symbol);
        if (existingTimeout) clearTimeout(existingTimeout);
        const timeout = setTimeout(() => {
          setRecentlyUpdated(prev => {
            const next = new Set(prev);
            next.delete(update.symbol);
            return next;
          });
          updateTimeoutRef.current.delete(update.symbol);
        }, 600); // Flash for 600ms
        updateTimeoutRef.current.set(update.symbol, timeout);
        return updatedStocks;
      });
      // Update lastUpdatedTime whenever a price update is received
      setLastUpdatedTime(new Date().toLocaleTimeString());
    };

    const handleMarketStatus = (event: CustomEvent<StreamMarketStatus>) => {
      const status = event.detail;
      // Check if this is a market status event (has status) vs other event types
      if (!status.status) return;
      setCurrentMarketStatus(status.status);
      // Update lastUpdatedTime with the timestamp from the status event
      if (status.timestamp) {
        const time = new Date(status.timestamp).toLocaleTimeString();
        if (time !== 'Invalid Date') setLastUpdatedTime(time);
      } else {
        setLastUpdatedTime(new Date().toLocaleTimeString());
      }
    };

    window.addEventListener('ggui:agent-data', handlePriceUpdate as EventListener);
    window.addEventListener('ggui:agent-data', handleMarketStatus as EventListener);

    return () => {
      window.removeEventListener('ggui:agent-data', handlePriceUpdate as EventListener);
      window.removeEventListener('ggui:agent-data', handleMarketStatus as EventListener);
    };
  }, []);

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      updateTimeoutRef.current.forEach(timeout => clearTimeout(timeout));
    };
  }, []);

  return {
    stocks,
    recentlyUpdated,
    currentMarketStatus,
    lastUpdatedTime,
  };
}

